  22→/// How many functions to sample.
  23→#[derive(Debug, Clone)]
  24→pub enum SampleBudget {
  25→    /// A percentage of total functions (0.0..=100.0).
  26→    Percentage(f64),
  27→    /// An absolute function count.
  28→    Absolute(usize),
  29→}
  30→
  31→/// Configuration for core sample selection.
  32→#[derive(Debug, Clone)]
  33→pub struct CoreSampleConfig {
  34→    /// Budget: how many functions to select.
  35→    pub budget: SampleBudget,
  36→    /// Seed for deterministic selection.
  37→    pub seed: u64,
  38→    /// Root directory of the scan (for computing relative module paths).
  39→    pub scan_root: String,
  40→}
