 165→    depth: usize,
 166→    kind: FunctionKind,
 167→}
 168→
 169→impl StratumKey {
 170→    fn label(&self) -> String {
 171→        format!(
 172→            "{} | {} | depth={} | {}",
 173→            self.module,
 174→            self.complexity.label(),
 175→            self.depth,
 176→            self.kind.label(),
 177→        )
 178→    }
 179→}
