 384→/// Compute a default seed from a project directory and optional git HEAD.
 385→pub fn default_seed(scan_dir: &str) -> u64 {
 386→    let mut hasher = DefaultHasher::new();
 387→    scan_dir.hash(&mut hasher);
 388→    // Try to incorporate git HEAD for reproducibility across unchanged commits.
 389→    if let Ok(output) = std::process::Command::new("git")
 390→        .args(["rev-parse", "HEAD"])
 391→        .current_dir(scan_dir)
 392→        .output()
 393→        && output.status.success()
 394→    {
 395→        output.stdout.hash(&mut hasher);
 396→    }
 397→    hasher.finish()
 398→}
