    /// Per-stratum breakdown for reporting.
    pub strata_summary: Vec<StratumInfo>,
}

impl CoreSampleResult {
    /// All functions that should be included (selected + closure).
    pub fn all_included(&self) -> HashSet<String> {
        self.selected
